import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { CloseIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Tag.module.css';

export type TagVariant = 'default' | 'secondary' | 'outline' | 'ghost' | 'destructive';
export type TagSize = 'sm' | 'md';
export type TagRootProps = HTMLArkProps<'span'> & {
  variant?: TagVariant;
  size?: TagSize;
};
export type TagLabelProps = HTMLArkProps<'span'>;
export type TagStartElementProps = HTMLArkProps<'span'>;
export type TagEndElementProps = HTMLArkProps<'span'>;
export type TagCloseTriggerProps = HTMLArkProps<'button'>;

const DEFAULT_CLOSE_LABEL = 'Remove tag';

const TagRoot = forwardRef<HTMLSpanElement, TagRootProps>(function TagRoot(
  { className, size = 'md', variant = 'default', ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="tag"
      data-part="root"
      data-slot="tag-root"
      data-size={size}
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagLabel = forwardRef<HTMLSpanElement, TagLabelProps>(function TagLabel(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="tag"
      data-part="label"
      data-slot="tag-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagStartElement = forwardRef<HTMLSpanElement, TagStartElementProps>(function TagStartElement(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="tag"
      data-part="start-element"
      data-slot="tag-start-element"
      className={clsx(styles.startElement, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagEndElement = forwardRef<HTMLSpanElement, TagEndElementProps>(function TagEndElement(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="tag"
      data-part="end-element"
      data-slot="tag-end-element"
      className={clsx(styles.endElement, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagCloseTrigger = forwardRef<HTMLButtonElement, TagCloseTriggerProps>(
  function TagCloseTrigger(
    {
      asChild,
      className,
      children,
      disabled,
      onClick,
      type,
      'aria-disabled': ariaDisabled,
      'aria-label': ariaLabel,
      'aria-labelledby': ariaLabelledBy,
      ...props
    },
    ref,
  ) {
    const isDisabled = disabled || ariaDisabled === true || ariaDisabled === 'true';

    return (
      <ark.button
        ref={ref}
        asChild={asChild}
        type={asChild ? type : (type ?? 'button')}
        disabled={disabled}
        data-scope="tag"
        data-part="close-trigger"
        data-slot="tag-close-trigger"
        data-disabled={isDisabled ? '' : undefined}
        className={clsx(styles.closeTrigger, normalizeClassName(className))}
        aria-disabled={ariaDisabled}
        aria-label={
          ariaLabel ??
          (children == null && ariaLabelledBy == null ? DEFAULT_CLOSE_LABEL : undefined)
        }
        aria-labelledby={ariaLabelledBy}
        onClick={(event) => {
          if (isDisabled) {
            event.preventDefault();
            event.stopPropagation();
            return;
          }

          onClick?.(event);
        }}
        {...props}
      >
        {children ?? <CloseIcon />}
      </ark.button>
    );
  },
);

const Tag = Object.assign(TagRoot, {
  Root: TagRoot,
  Label: TagLabel,
  StartElement: TagStartElement,
  EndElement: TagEndElement,
  CloseTrigger: TagCloseTrigger,
});

export { Tag };

@layer ui.components {
  .root {
    display: inline-flex;
    width: fit-content;
    max-width: 100%;
    min-width: 0;
    box-sizing: border-box;
    align-items: center;
    gap: var(--tag-gap, 0.375rem);
    border: var(--tag-border-width, var(--border-width-sm)) solid
      var(--tag-border-color, transparent);
    border-radius: var(--tag-radius, var(--radius-full));
    background-color: var(--tag-bg, var(--color-primary));
    color: var(--tag-color, var(--color-primary-foreground));
    font-size: var(--tag-font-size, var(--text-xs));
    font-weight: var(--tag-font-weight, var(--weight-medium));
    line-height: var(--tag-line-height, var(--line-height-text-xs));
    min-height: var(--tag-height-md, 1.5rem);
    padding-block: var(--tag-padding-y-md, 0.125rem);
    padding-inline: var(--tag-padding-x-md, 0.5rem);
    white-space: nowrap;
    vertical-align: middle;
    transition:
      color var(--tag-transition, var(--transition-default)),
      background-color var(--tag-transition, var(--transition-default)),
      border-color var(--tag-transition, var(--transition-default));

    > svg {
      width: var(--tag-icon-size, 0.75rem);
      height: var(--tag-icon-size, 0.75rem);
      flex-shrink: 0;
      pointer-events: none;
    }

    &[data-size='sm'] {
      gap: var(--tag-gap-sm, 0.25rem);
      min-height: var(--tag-height-sm, 1.25rem);
      padding-block: var(--tag-padding-y-sm, 0);
      padding-inline: var(--tag-padding-x-sm, 0.375rem);
    }

    &[data-variant='secondary'] {
      background-color: var(--tag-bg, var(--color-secondary));
      border-color: var(--tag-border-color, transparent);
      color: var(--tag-color, var(--color-secondary-foreground));
    }

    &[data-variant='outline'] {
      background-color: var(--tag-bg, transparent);
      border-color: var(--tag-border-color, var(--color-border));
      color: var(--tag-color, var(--color-foreground));
    }

    &[data-variant='ghost'] {
      background-color: var(--tag-bg, transparent);
      border-color: var(--tag-border-color, transparent);
      color: var(--tag-color, var(--color-foreground));
    }

    &[data-variant='destructive'] {
      background-color: var(--tag-bg, var(--color-destructive));
      border-color: var(--tag-border-color, transparent);
      color: var(--tag-color, var(--color-primary-foreground));
    }
  }

  .label {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .startElement,
  .endElement {
    display: inline-flex;
    min-width: 0;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;

    > svg {
      width: var(--tag-icon-size, 0.75rem);
      height: var(--tag-icon-size, 0.75rem);
      flex-shrink: 0;
      pointer-events: none;
    }
  }

  .closeTrigger {
    display: inline-flex;
    width: var(--tag-close-trigger-size, 1rem);
    height: var(--tag-close-trigger-size, 1rem);
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    border: 0;
    border-radius: var(--tag-close-trigger-radius, var(--radius-full));
    padding: 0;
    background-color: var(--tag-close-trigger-bg, transparent);
    color: inherit;
    cursor: pointer;
    transition:
      color var(--tag-transition, var(--transition-default)),
      background-color var(--tag-transition, var(--transition-default)),
      box-shadow var(--tag-transition, var(--transition-default));

    > svg {
      width: var(--tag-close-trigger-icon-size, 0.625rem);
      height: var(--tag-close-trigger-icon-size, 0.625rem);
      flex-shrink: 0;
      pointer-events: none;
    }

    &:hover {
      background-color: var(
        --tag-close-trigger-bg-hover,
        color-mix(in oklab, currentColor 12%, transparent)
      );
    }

    &:focus-visible {
      outline: none;
      box-shadow:
        0 0 0 var(--tag-close-trigger-focus-ring-offset, 0)
          var(--tag-close-trigger-focus-ring-offset-color, transparent),
        0 0 0
          calc(
            var(--tag-close-trigger-focus-ring-width, var(--border-width-sm)) +
              var(--tag-close-trigger-focus-ring-offset, 0)
          )
          var(--tag-close-trigger-focus-ring-color, var(--color-ring));
    }

    &[disabled],
    &[data-disabled] {
      cursor: default;
      opacity: var(--tag-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
  }
}

export { Tag } from './Tag';
export type {
  TagCloseTriggerProps,
  TagEndElementProps,
  TagLabelProps,
  TagRootProps,
  TagSize,
  TagStartElementProps,
  TagVariant,
} from './Tag';
